const item = $input.first();
const binaryData = item.binary?.data;

if (!binaryData) {
  throw new Error(`No binary data for file: ${item.json.file_id}`);
}

const base64Image = binaryData.data;
const mimeType = binaryData.mimeType || 'image/jpeg';

return [{
  json: {
    file_id:     $('Loop Over Files1').first().json.file_id,
    file_name:   $('Loop Over Files1').first().json.file_name,
    folder_id:   $('Loop Over Files1').first().json.folder_id,
    folder_name: $('Loop Over Files1').first().json.folder_name,
    base64_image: base64Image,
    mime_type:   mimeType,
  }
}];

const driveItems = $('Get Drive Files1').all();
const processedData = $('Get Processed IDs1').first().json;
const processedIds = new Set(processedData.processed_file_ids || []);

const IMAGE_TYPES = [
  'image/jpeg', 'image/jpg', 'image/png', 'image/gif',
  'image/webp', 'image/tiff', 'application/pdf'
];

function flatten(items, folderName = '', folderId = '') {
  const result = [];
  for (const item of items) {
    if (item.mimeType === 'application/vnd.google-apps.folder') {
      result.push(...flatten(item.children || [], item.name, item.id));
    } else if (IMAGE_TYPES.includes(item.mimeType)) {
      result.push({
        file_id: item.id,
        file_name: item.name,
        mime_type: item.mimeType,
        folder_id: folderId,
        folder_name: folderName,
        modified_time: item.modifiedTime,
      });
    }
  }
  return result;
}

const allFiles = [];
for (const driveItem of driveItems) {
  const folders = Array.isArray(driveItem.json) ? driveItem.json : [driveItem.json];
  allFiles.push(...flatten(folders));
}

const newFiles = allFiles.filter(f => !processedIds.has(f.file_id));

if (newFiles.length === 0) {
  console.log('No new files to process.');
  return [];
}

console.log(`Found ${newFiles.length} new file(s) to process.`);
return newFiles.map(f => ({ json: f }));

const item = $input.first();
const openaiResponse = item.json;

// OpenAI response format: choices[0].message.content
const replyText = openaiResponse?.choices?.[0]?.message?.content;
if (!replyText) {
  throw new Error('GPT-4o returned no content');
}

let ocrData;
try {
  const cleaned = replyText
    .replace(/```json/gi, '')
    .replace(/```/g, '')
    .trim();
  ocrData = JSON.parse(cleaned);
} catch (e) {
  console.error('Failed to parse GPT-4o OCR response:', replyText);
  ocrData = {
    document_type: 'unknown',
    vat_type: 'unknown',
    expense_category: 'uncategorized',
    business_name: '',
    total: 0,
  };
}

const fileMeta = $('Prepare Vision Request').first().json;

const receiptPayload = {
  drive_file_id:    fileMeta.file_id,
  drive_file_name:  fileMeta.file_name,
  drive_folder_id:  fileMeta.folder_id,
  drive_folder_name: fileMeta.folder_name,
  status: 'processed',
  ocr_raw_text: replyText,

  document_type:    ocrData.document_type    || 'unknown',
  vat_type:         ocrData.vat_type         || 'unknown',
  expense_category: ocrData.expense_category || 'uncategorized',
  business_name:    ocrData.business_name    || '',
  business_address: ocrData.business_address || '',
  tin:              ocrData.tin              || '',
  receipt_number:   ocrData.receipt_number   || '',
  bir_permit_number: ocrData.bir_permit_number || '',
  expense_date:     ocrData.expense_date     || '',
  description:      ocrData.description      || '',
  buyer_name:       ocrData.buyer_name       || '',
  buyer_tin:        ocrData.buyer_tin        || '',

  subtotal:         Number(ocrData.subtotal)         || 0,
  vatable_sales:    Number(ocrData.vatable_sales)    || 0,
  vat_exempt_sales: Number(ocrData.vat_exempt_sales) || 0,
  zero_rated_sales: Number(ocrData.zero_rated_sales) || 0,
  vat_amount:       Number(ocrData.vat_amount)       || 0,
  total:            Number(ocrData.total)            || 0,
};

return [{ json: receiptPayload }];

const saved = $input.first().json;
console.log(`Receipt saved: ID=${saved.receipt_id}, created=${saved.created}, file=${saved.drive_file_id}`);
return $input.all();

const webhookBody    = $('Receive Chat Message1').first().json.body;
const memoryData     = $('Fetch User Memory1').first().json;
const analyticsData  = $('Fetch Analytics Data1').first().json;

const userId          = webhookBody.user_id;
const userMessage     = webhookBody.message;
const conversationId  = webhookBody.conversation_id || null;
const history         = webhookBody.history || [];

// Build analytics block
const summary  = analyticsData.summary  || {};
const byCategory = analyticsData.by_category || [];
const recent   = analyticsData.recent_receipts || [];

const analyticsBlock = `
=== USER FINANCIAL SUMMARY ===
Total Receipts : ${summary.total_receipts    ?? 'N/A'}
Total Spent    : PHP ${summary.total_amount  ?? '0.00'}
This Month     : PHP ${summary.this_month    ?? '0.00'}
Last Month     : PHP ${summary.last_month    ?? '0.00'}
Avg per Receipt: PHP ${summary.average_amount ?? '0.00'}

Top Categories:
${byCategory.slice(0, 5).map(c => `  - ${c.category}: PHP ${c.total} (${c.count} receipts)`).join('\n')}

Recent Receipts (last 5):
${recent.slice(0, 5).map(r => `  - ${r.expense_date} | ${r.business_name} | PHP ${r.total} | ${r.expense_category}`).join('\n')}
`.trim();

// Build memory block
const memories = memoryData.messages || [];
const memoryBlock = memories.length > 0
  ? `=== RELEVANT PAST CONVERSATIONS ===\n${memories.map(m => `[${m.role}]: ${m.content}`).join('\n')}`
  : '';

// System prompt
const systemPrompt = `You are Lifewood's AI finance assistant. You help users understand their expense history, receipts, and spending patterns.

Guidelines:
- Be concise and professional
- Always reference actual data when answering
- Format currency as PHP X,XXX.XX
- If asked about something not in the data, say so honestly
- You can only see this user's own data

${analyticsBlock}

${memoryBlock}`.trim();

// Build messages array from history (last 10 turns)
const historyMessages = history.slice(-10).map(h => ({
  role: h.role === 'agent' ? 'assistant' : 'user',
  content: h.content
}));

// Final messages array for OpenAI
const messages = [
  { role: 'system', content: systemPrompt },
  ...historyMessages,
  { role: 'user',   content: userMessage }
];

return [{
  json: {
    messages,
    user_id: userId,
    conversation_id: conversationId,
    user_message: userMessage,
  }
}];

const openaiResponse  = $('GPT-4o Chat').first().json;
const buildData       = $('Build System Prompt').first().json;

const replyText = openaiResponse?.choices?.[0]?.message?.content;
if (!replyText) {
  throw new Error('GPT-4o returned no reply content');
}

const usage = openaiResponse.usage || {};

return [{
  json: {
    reply:           replyText,
    conversation_id: buildData.conversation_id,
    user_id:         buildData.user_id,
    metadata: {
      model:              openaiResponse.model,
      input_tokens:       usage.prompt_tokens,
      output_tokens:      usage.completion_tokens,
      total_tokens:       usage.total_tokens,
    }
  }
}];
